// Topic convention: uns/{site}/{system}/{device}/{type}
// Example: uns/site01/hvac/opta-ahu01/telemetry

const parts = msg.topic.split("/");

if (parts.length < 5) {
    node.warn("Unexpected topic structure: " + msg.topic);
    return null;
}

msg.meta = {
    namespace: parts[0],
    site:      parts[1],
    system:    parts[2],
    device:    parts[3],
    type:      parts[4]
};

return msg;

// STUB: InfluxDB write pipeline goes here in the next phase.
// Will receive: msg.payload = { meta, telemetry, timestamp }
//
// Next step: add influxdb-out node and map fields:
//   measurement: msg.payload.meta.system + "." + msg.payload.meta.device
//   fields:      msg.payload.telemetry
//   timestamp:   msg.payload.timestamp

node.status({ fill: "grey", shape: "ring", text: "historian stub — not connected" });
return null;

// Input:  msg.payload = Arduino Opta AHU telemetry
//         msg.meta    = { namespace, site, system, device, type }
//
// Output: msg.payload = clean domain object

const raw = msg.payload;

// Validate required fields from Opta firmware
if (raw.supply_air_temp_c === undefined || raw.return_air_temp_c === undefined) {
    node.warn("AHU payload missing required fields: " + JSON.stringify(raw));
    return null;
}

msg.payload = {
    meta: {
        site:   msg.meta.site,
        system: msg.meta.system,
        device: raw.device || msg.meta.device,
        type:   "ahu",
        mode:   raw.mode
    },
    telemetry: {
        // Air side
        supply_air_temp_c:     raw.supply_air_temp_c,
        supply_air_setpoint_c: raw.supply_air_setpoint_c,
        return_air_temp_c:     raw.return_air_temp_c,

        // Chilled water side
        chw_temp_in_c:         raw.chw_temp_in_c,
        chw_temp_out_c:        raw.chw_temp_out_c,
        chw_delta_t_c:         raw.chw_delta_t_c,

        // Mechanical
        vfd_speed_pct:         raw.vfd_speed_pct,
        vfd_setpoint_pct:      raw.vfd_setpoint_pct,
        valve_position_pct:    raw.valve_position_pct,
        filter_dp_pa:          raw.filter_dp_pa,
        duct_pressure_pa:      raw.duct_pressure_pa,

        // Air quality
        co2_ppm:               raw.co2_ppm
    },
    timestamp: raw.event_ts || Date.now(),
    uptime_ms: raw.uptime_ms
};

return msg;
